      process.exit(0);
    } catch (err) {
      console.error('Ошибка при shutdown:', err);
      process.exit(1);
    }
  });

  // Принудительный выход через 30с если shutdown завис
  setTimeout(() => {
    console.error('Принудительный shutdown по таймауту');
    process.exit(1);
  }, 30_000).unref(); // unref: не держать event loop ради этого таймера
}

process.on('SIGTERM', () => gracefulShutdown('SIGTERM')); // Kubernetes отправляет это
process.on('SIGINT', () => gracefulShutdown('SIGINT'));   // Ctrl+C

