subscribe('undici:request:create', ({ request }) => {
  const traceId = getTraceId(); // из ALS
  request.addHeader('x-trace-id', traceId);
});

subscribe('undici:request:trailers', ({ request, trailers }) => {
  console.log(`HTTP ${request.method} ${request.path}: готово`);
});

